#include "LODComponentData.h"
#include "ArgusLogging.h"
#include "ArgusStaticData.h"

void ULODComponentData::InstantiateComponentForEntity(ArgusEntity entity) const
{
	LODComponent* LODComponentRef = entity.GetOrAddComponent<LODComponent>();
	ARGUS_RETURN_ON_NULL(LODComponentRef, ArgusECSLog);

}

void ULODComponentData::ReinitializeComponentForEntityPostLoad(ArgusEntity entity) const
{
	LODComponent* LODComponentRef = entity.GetComponent<LODComponent>();
	ARGUS_RETURN_ON_NULL(LODComponentRef, ArgusECSLog);

}

void ULODComponentData::OnComponentDataLoaded() const
{
}

bool ULODComponentData::MatchesType(const UComponentData* other) const
{
	if (!other)
	{
		return false;
	}

	return other->IsA<ULODComponentData>();
}
